import React, { useEffect, useState } from "react";

function App() {
  const [incidents, setIncidents] = useState([]);
  const [component, setComponent] = useState("");
  const [message, setMessage] = useState("");
  const [selectedIncident, setSelectedIncident] = useState(null);
  const [showRCAForm, setShowRCAForm] = useState(null);
  const [view, setView] = useState("ACTIVE");
  const [toast, setToast] = useState("");

  const [rcaData, setRcaData] = useState({
    category: "",
    start: "",
    end: "",
    root: "",
    fix: "",
    prevention: "",
  });

  // Toast
  const showToast = (msg) => {
    setToast(msg);
    setTimeout(() => setToast(""), 3000);
  };

  // Fetch + sort
  const fetchIncidents = async () => {
    const res = await fetch("http://127.0.0.1:8000/incidents");
    const data = await res.json();

    const priority = { P0: 1, P1: 2, P2: 3 };

    const sorted = data.sort(
      (a, b) => priority[a.severity] - priority[b.severity]
    );

    setIncidents(sorted);
  };

  useEffect(() => {
    fetchIncidents();
    const interval = setInterval(fetchIncidents, 3000);
    return () => clearInterval(interval);
  }, []);

  // Status steps
  const getStatusSteps = (current) => {
    const steps = ["OPEN", "INVESTIGATING", "RESOLVED", "CLOSED"];
    return steps.map((step) => ({
      name: step,
      active: step === current,
      completed: steps.indexOf(step) < steps.indexOf(current),
    }));
  };

  // Send signal
  const sendSignal = async () => {
    if (!component || !message) {
      showToast("⚠️ Enter Component & Message");
      return;
    }

    await fetch(
      `http://127.0.0.1:8000/ingest?component_id=${component}&message=${message}`,
      { method: "POST" }
    );

    showToast("✅ Incident Created");
    setComponent("");
    setMessage("");
    fetchIncidents();
  };

  // Status update
  const updateStatus = async (id, status) => {
    await fetch(
      `http://127.0.0.1:8000/incident/${id}/status?status=${status}`,
      { method: "PUT" }
    );

    showToast(`Moved to ${status}`);
    fetchIncidents();
  };

  // Close
  const closeIncident = async (id) => {
    const res = await fetch(
      `http://127.0.0.1:8000/incident/${id}/status?status=CLOSED`,
      { method: "PUT" }
    );

    const data = await res.json();

    if (!res.ok) {
      showToast(data.detail);
    } else {
      showToast("Incident Closed");
    }

    fetchIncidents();
  };

  // Submit RCA
  const submitRCA = async (id) => {
    if (!rcaData.root || !rcaData.fix) {
      showToast("Fill required fields");
      return;
    }

    await fetch(
      `http://127.0.0.1:8000/incident/${id}/rca?root_cause=${rcaData.root}&fix=${rcaData.fix}`,
      { method: "POST" }
    );

    showToast("RCA Added");
    setShowRCAForm(null);
    setRcaData({
      category: "",
      start: "",
      end: "",
      root: "",
      fix: "",
      prevention: "",
    });

    fetchIncidents();
  };

  const filteredIncidents =
    view === "ACTIVE"
      ? incidents.filter((i) => i.status !== "CLOSED")
      : incidents.filter((i) => i.status === "CLOSED");

  return (
    <div
      style={{
        padding: "20px",
        fontFamily: "Arial",
        background: "#f5f7fa",
        minHeight: "100vh",
      }}
    >
      {/* Toast */}
      {toast && (
        <div
          style={{
            position: "fixed",
            top: "20px",
            right: "20px",
            background: "#2ecc71",
            color: "#fff",
            padding: "10px 15px",
            borderRadius: "6px",
          }}
        >
          {toast}
        </div>
      )}

      <h1>🚨 Incident Dashboard</h1>

      {/* Input */}
      <div style={{ display: "flex", gap: "10px", marginBottom: "20px" }}>
        <input
          placeholder="Component"
          value={component}
          onChange={(e) => setComponent(e.target.value)}
          style={{ flex: 1 }}
        />
        <input
          placeholder="Message"
          value={message}
          onChange={(e) => setMessage(e.target.value)}
          style={{ flex: 1 }}
        />
        <button onClick={sendSignal}>Send</button>
      </div>

      {/* Toggle */}
      <div>
        <button onClick={() => setView("ACTIVE")}>Active</button>
        <button onClick={() => setView("CLOSED")}>Closed</button>
      </div>

      <h2>
        {view} Incidents ({filteredIncidents.length})
      </h2>

      {/* Cards */}
      {filteredIncidents.map((inc) => (
        <div
          key={inc.id}
          onClick={() =>
            setSelectedIncident(selectedIncident === inc.id ? null : inc.id)
          }
          style={{
            background: "#fff",
            padding: "15px",
            margin: "10px 0",
            borderRadius: "8px",
          }}
        >
          <h3>Incident #{inc.id}</h3>

          <p><b>Component:</b> {inc.component_id}</p>

          <p><b>Severity:</b> {inc.severity}</p>

          {/* Status */}
          <div style={{ display: "flex" }}>
            {getStatusSteps(inc.status).map((s, i) => (
              <div key={i}>{s.name}</div>
            ))}
          </div>

          <p><b>Signals:</b> {inc.signals.length}</p>

          {/* Expand signals */}
          {selectedIncident === inc.id && (
            <div>
              {inc.signals.map((s, i) => (
                <div key={i}>
                  {s.message} - {new Date(s.timestamp).toLocaleString()}
                </div>
              ))}
            </div>
          )}

          {/* RCA */}
          {inc.rca && (
            <div>
              <p><b>Root:</b> {inc.rca.root_cause}</p>
              <p><b>Fix:</b> {inc.rca.fix}</p>
            </div>
          )}

          {/* Buttons */}
          <button onClick={(e)=>{e.stopPropagation();updateStatus(inc.id,"INVESTIGATING")}}>Investigate</button>
          <button onClick={(e)=>{e.stopPropagation();updateStatus(inc.id,"RESOLVED")}}>Resolve</button>
          <button onClick={(e)=>{e.stopPropagation();setShowRCAForm(inc.id)}}>Add RCA</button>
          <button onClick={(e)=>{e.stopPropagation();closeIncident(inc.id)}}>Close</button>

          {/* RCA FORM */}
          {showRCAForm === inc.id && (
            <div onClick={(e)=>e.stopPropagation()}>
              <h4>RCA Form</h4>

              <select onChange={(e)=>setRcaData({...rcaData,category:e.target.value})}>
                <option>Select Category</option>
                <option>Infrastructure</option>
                <option>Application</option>
                <option>Network</option>
              </select>

              <input type="datetime-local" onChange={(e)=>setRcaData({...rcaData,start:e.target.value})}/>
              <input type="datetime-local" onChange={(e)=>setRcaData({...rcaData,end:e.target.value})}/>

              <input placeholder="Root Cause" onChange={(e)=>setRcaData({...rcaData,root:e.target.value})}/>
              <textarea placeholder="Fix Applied" onChange={(e)=>setRcaData({...rcaData,fix:e.target.value})}/>
              <textarea placeholder="Prevention Steps" onChange={(e)=>setRcaData({...rcaData,prevention:e.target.value})}/>

              <button onClick={()=>submitRCA(inc.id)}>Submit</button>
            </div>
          )}
        </div>
      ))}
    </div>
  );
}

export default App;
